  ?loc dbo:country dbr:Germany .
} ORDER BY DESC(?height) LIMIT 1", "question": "What is the highest mountain in Germany?"}

{"query": "SELECT ?mountain WHERE {
  ?mountain a dbo:Mountain .
  ?mountain dbo:country dbr:Germany .
  ?mountain dbp:height ?height .
} ORDER BY DESC(?height) LIMIT 1", "question": "What is the highest mountain in Germany?"}

{"query": "SELECT ?mountain WHERE {
  ?mountain a dbo:Mountain .
  ?mountain dbo:country dbr:Germany .
  OPTIONAL { ?mountain dbp:height ?height1 . }
  OPTIONAL { ?mountain dbo:elevation ?height2 . }
  BIND(COALESCE(?height1, ?height2) AS ?height)
  FILTER(BOUND(?height))
} ORDER BY DESC(?height)
LIMIT 1", "question": "What is the highest mountain in Germany?"}

